// ABI guard fingerprint for the generated arena layout.
//
// SHA-256(role|memory|source_memory|size|alignment|is_staged) over
// every region in region_id order, truncated to 16 hex chars. Stays
// stable across re-plans of the same model and changes whenever any
// region's role / memory residency / size / alignment / staged
// status changes. Downstream binaries that hard-code arena region
// IDs can validate this matches the planner that built their loader
// before binding arenas.
#define RESNET_PLAN_HASH "19d806b6ac17194f"

